UPDATE tb_password
SET approver_name = #{approverName}, approved_at = #{approvedAt}, status = 'APPROVED'
WHERE pw_id = #{pwId}

UPDATE tb_password
SET rejected_by = #{rejectedBy}, rejected_at = #{rejectedAt}, reject_reason = #{rejectReason}, status = 'REJECTED'
WHERE pw_id = #{pwId}

UPDATE tb_password
SET status = 'PENDING', rejected_by = NULL, rejected_at = NULL, reject_reason = NULL
WHERE pw_id = #{pwId}
